section.codeblock:
apiVersion: "k8s.cni.cncf.io/v1"
kind: NetworkAttachmentDefinition
metadata:
  name: nad-vswitch-bd3002
spec:
  config: '{
    "cniVersion":"0.4.0",
    "name": "nad-vswitch-bd3002",
    "capabilities":{"ips":true},
    "plugins": [
      {
        "type": "jcnr",
        "args": {
          "instanceName": "vswitch",                       <--- Do not change
          "instanceType": "virtual-switch",                <--- Do not change
          "bridgeDomain": "bd3002",                        <--- Configurable 
          "bridgeVlanId": "3002",                          <--- Configurable
          "dataplane":"dpdk",                              <--- dpdk or kernel
          "mtu": "9000"
        },
        "ipam": {
          "type": "static",
          "capabilities":{"ips":true},
          "addresses":[
            {
              "address":"2001:db8:3002::10.2.0.1/64",
              "gateway":"2001:db83002::10.2.0.254"
            },
            {
              "address":"10.2.0.1/24",
              "gateway":"10.2.0.254"
            }
          ]
        },
        "kubeConfig":"/etc/kubernetes/kubelet.conf"
      }
    ]
  }'

apiVersion: "k8s.cni.cncf.io/v1"
kind: NetworkAttachmentDefinition
metadata:
  name: pod1-vswitch-bd3001-1
spec:
  config: '{
    "cniVersion":"0.4.0",
    "name": "pod1-vswitch-bd3001-1",
    "capabilities":{"ips":true},
    "plugins": [
      {
        "type": "jcnr",
        "args": {
          "instanceName": "vswitch",                        <--- Do not change
          "instanceType": "virtual-switch",                 <--- Do not change
          "bridgeDomain": "bd3001",                         <--- Configurable 
          "bridgeVlanId": "3001",                           <--- Configurable 
          "dataplane":"dpdk",                               <--- dpdk or kernel 
          "mtu": "9000",
          "interfaceType":"veth"                            <--- for not DPDK applications (OAM) 
        },
        "ipam": {
          "type": "static",
          "capabilities":{"ips":true},
          "addresses":[
            {
              "address":"2001:db8:3001::10.1.0.1/64",
              "gateway":"2001:db8:3001::10.1.0.254"
            },
            {
              "address":"10.1.0.1/24",
              "gateway":"10.1.0.254"
            }
          ]
        },
        "kubeConfig":"/etc/kubernetes/kubelet.conf"
      }
    ]
  }'

apiVersion: "k8s.cni.cncf.io/v1"
kind: NetworkAttachmentDefinition
metadata:
  name: vswitch-bd3003-sub      
spec:
  config: '{
    "cniVersion":"0.4.0",
    "name": "vswitch-bd3003-sub",
    "capabilities":{"ips":true},
    "plugins": [
      {
        "type": "jcnr",
        "args": {
          "instanceName": "vswitch",                  <--- Do not change
          "instanceType": "virtual-switch",           <--- Do not change
          "bridgeDomain": "bd3003",                   <--- Configurable
          "bridgeVlanId": "3003",                     <--- Configurable
          "parentInterface":"net1",                   <--- Configurable
          "interface":"net1.3003",                    <--- Configurable
          "dataplane":"dpdk"                          <--- dpdk or kernel
        },
        "ipam": {
          "type": "static",
          "capabilities":{"ips":true},
          "addresses":[
            {
              "address":"10.3.0.1/24",
              "gateway":"10.3.0.254"
            },
            {
              "address":"2001:db8:3003::10.3.0.1/120",
              "gateway":"2001:db8:3003::10.3.0.1"
            }
          ]
        },
        "kubeConfig":"/etc/kubernetes/kubelet.conf"
      }
    ]
  }'

